using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability using the DuckDuckGo Instant Answer API.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a topic. Returns relevant snippets and related topics.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        using var response = await _httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var results = new List<string>();

        // Extract abstract (main answer)
        var abstractText = root.GetProperty("Abstract").GetString();
        var abstractSource = root.GetProperty("AbstractSource").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.Add($"[{abstractSource}] {abstractText}");
        }

        // Extract related topics
        if (root.TryGetProperty("RelatedTopics", out var relatedTopics))
        {
            foreach (var topic in relatedTopics.EnumerateArray().Take(8))
            {
                if (topic.TryGetProperty("Text", out var text) &&
                    !string.IsNullOrWhiteSpace(text.GetString()))
                {
                    var topicUrl = topic.TryGetProperty("FirstURL", out var firstUrl)
                        ? firstUrl.GetString() : null;
                    var entry = topicUrl is not null
                        ? $"- {text.GetString()} (source: {topicUrl})"
                        : $"- {text.GetString()}";
                    results.Add(entry);
                }
            }
        }

        // Extract answer (for computation/instant answers)
        var answer = root.GetProperty("Answer").GetString();
        if (!string.IsNullOrWhiteSpace(answer))
        {
            results.Add($"Instant answer: {answer}");
        }

        return results.Count > 0
            ? string.Join("\n", results)
            : $"No results found for '{query}'. Try rephrasing or breaking the query into simpler terms.";
    }

    public IEnumerable<AIFunction> AsFunctions() =>
        AIFunctionFactory.Create(SearchWebAsync, this);
}

using System.Collections.Concurrent;
using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides in-memory note-taking capability for the research agent.
/// Notes are stored by topic key for organized retrieval.
/// </summary>
public sealed class NoteTool
{
    private readonly ConcurrentDictionary<string, List<string>> _notes = new(StringComparer.OrdinalIgnoreCase);

    [Description("Save a research note under a topic. Use this to record important findings during research.")]
    public string AddNote(
        [Description("The topic or category for the note (e.g. 'key_findings', 'statistics', 'sources')")] string topic,
        [Description("The content of the note to save")] string content)
    {
        var notes = _notes.GetOrAdd(topic, _ => []);
        lock (notes)
        {
            notes.Add(content);
        }

        return $"Note saved under '{topic}' ({notes.Count} note(s) total).";
    }

    [Description("Retrieve all saved notes, optionally filtered by topic. Use this to review findings before summarizing.")]
    public string GetNotes(
        [Description("Optional topic filter. Leave empty to get all notes.")] string? topic = null)
    {
        if (!string.IsNullOrWhiteSpace(topic))
        {
            if (_notes.TryGetValue(topic, out var topicNotes))
            {
                lock (topicNotes)
                {
                    return $"Notes for '{topic}':\n" + string.Join("\n", topicNotes.Select((n, i) => $"  {i + 1}. {n}"));
                }
            }

            return $"No notes found for topic '{topic}'.";
        }

        if (_notes.IsEmpty)
        {
            return "No notes have been saved yet.";
        }

        var allNotes = new List<string>();
        foreach (var (key, notes) in _notes.OrderBy(kv => kv.Key))
        {
            lock (notes)
            {
                allNotes.Add($"[{key}] ({notes.Count} note(s))");
                allNotes.AddRange(notes.Select((n, i) => $"  {i + 1}. {n}"));
            }
        }

        return string.Join("\n", allNotes);
    }

    [Description("List all topic categories that have saved notes.")]
    public string ListTopics()
    {
        if (_notes.IsEmpty)
        {
            return "No topics yet.";
        }

        var topics = _notes.Select(kv => $"- {kv.Key} ({kv.Value.Count} note(s))");
        return "Saved topics:\n" + string.Join("\n", topics);
    }

    public IEnumerable<AIFunction> AsFunctions() =>
    [
        .. AIFunctionFactory.Create(AddNote, this),
        .. AIFunctionFactory.Create(GetNotes, this),
        .. AIFunctionFactory.Create(ListTopics, this),
    ];
}

