using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18";

// Build the IChatClient via the MEAI abstraction
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Create tool instances
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
var webSearch = new WebSearchTool(httpClient);
var notes = new NoteTool();

// Collect all tool functions
var tools = new List<AITool>();
tools.AddRange(webSearch.AsFunctions());
tools.AddRange(notes.AsFunctions());

// Create the research agent with Microsoft Agent Framework
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic provided by the user.

        Follow this workflow:
        1. Break the topic into 2-3 specific search queries.
        2. Use the SearchWebAsync tool to search for each query.
        3. Use the AddNote tool to save important findings organized by topic
           (e.g., 'key_findings', 'statistics', 'sources', 'definitions').
        4. After gathering enough information, use GetNotes to review everything you collected.
        5. Provide a well-structured summary with sections: Overview, Key Findings, and Sources.

        Always cite your sources. If a search returns no results, try rephrasing the query.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and organizing notes.",
    tools: tools);

// Configure run options with temperature and token limits
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent (MAF)           ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine("(The agent will search the web and take notes...)");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var session = new AgentSession();
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session,
            runOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

