1. using System.ComponentModel;
2. using System.Text.Json;
3. using Microsoft.Extensions.AI;
4. 
5. namespace ResearchAgent.Tools;
6. 
7. /// <summary>
8. /// Provides web search capability using the DuckDuckGo Instant Answer API.
9. /// </summary>
10. public sealed class WebSearchTool
11. {
12.     private readonly HttpClient _httpClient;
13. 
14.     public WebSearchTool(HttpClient httpClient)
15.     {
16.         _httpClient = httpClient;
17.     }
18. 
19.     [Description("Search the web for information on a topic. Returns relevant snippets and related topics.")]
20.     public async Task<string> SearchWebAsync(
21.         [Description("The search query to look up")] string query,
22.         CancellationToken cancellationToken = default)
23.     {
24.         var encoded = Uri.EscapeDataString(query);
25.         var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
26. 
27.         using var response = await _httpClient.GetAsync(url, cancellationToken);
28.         response.EnsureSuccessStatusCode();
29. 
30.         var json = await response.Content.ReadAsStringAsync(cancellationToken);
31.         var doc = JsonDocument.Parse(json);
32.         var root = doc.RootElement;
33. 
34.         var results = new List<string>();
35. 
36.         // Extract abstract (main answer)
37.         var abstractText = root.GetProperty("Abstract").GetString();
38.         var abstractSource = root.GetProperty("AbstractSource").GetString();
39.         if (!string.IsNullOrWhiteSpace(abstractText))
40.         {
41.             results.Add($"[{abstractSource}] {abstractText}");
42.         }
43. 
44.         // Extract related topics
45.         if (root.TryGetProperty("RelatedTopics", out var relatedTopics))
46.         {
47.             foreach (var topic in relatedTopics.EnumerateArray().Take(8))
